// I2C Slave Interface
module sync_down_counter_8bit_with_reset (
    input wire clk,
    input wire rst,
    input wire en,
    output reg [7:0] count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 8'b11111111;
        end else if (en) begin
            count <= count - 1;
        end
    end

endmodule
